query GetTheme($id: ID) {
  theme(id: $id) {
    ...DefaultThemeFields
    createdBy {
      id
      displayName
      email
      profileImageUrl
      __typename
    }
    __typename
  }
}

fragment DefaultThemeFields on Theme {
  id
  workspaceId
  name
  headingFont
  headingFontWeight
  bodyFont
  bodyFontWeight
  accentColor
  logoUrl
  config
  priority
  previewUrl
  archived
  createdTime
  updatedTime
  fonts {
    ... on ThemeFont {
      ...DefaultThemeFontFields
      __typename
    }
    __typename
  }
  __typename
}

fragment DefaultThemeFontFields on ThemeFont {
  id
  name
  url
  __typename
}
